// Normalize incoming page records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    pageId: String(j.pageId ?? j.id ?? '').trim(),
    url: typeof j.url === 'string' ? j.url.trim() : j.url ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

